mapper.select:
SELECT p.id, p.category_id AS categoryId, p.name, p.description, p.image, p.price, p.quantity AS stockQuantity, p.status_id AS statusId, CASE p.status_id WHEN 1 THEN 'ACTIVE' WHEN 2 THEN 'INACTIVE' WHEN 3 THEN 'OUT_OF_STOCK' END AS statusName, p.created_at AS createdAt, p.updated_at AS updatedAt, COUNT(*) OVER() AS total FROM products p WHERE 1 = 1
AND p.id = #{f.productId}
AND p.name ILIKE CONCAT('%', #{f.name}, '%')
AND p.category_id = #{f.categoryId}
AND p.status_id IN
#{s}
ORDER BY p.created_at DESC
LIMIT #{size} OFFSET (#{page} - 1) * #{size}
